let text = context.item.data?.content || '';

// 1. Sanitizar HTML básico para segurança
text = text.replace(/</g, "&lt;").replace(/>/g, "&gt;");

// 2. Bloco de Código (```texto```)
text = text.replace(/```([\s\S]+?)```/g, '<code style="background: #f0f0f0; padding: 2px 4px; border-radius: 3px; font-family: monospace;">$1</code>');

// 3. Listas / Bullet Points (Novo)
// Transforma linhas começando com "- ", "+ " ou "* " em uma bolinha (•)
// Nota: Processamos isso ANTES do negrito para não confundir o asterisco de lista com o de negrito.
text = text.replace(/(^|\n)(\s*)([-+*])\s+/g, '$1$2&#8226; ');

// 4. Negrito (*texto*)
// Regex ajustada: Exige espaço ou início antes, e espaço ou pontuação depois.
text = text.replace(/(^|\s)\*([^*]+)\*(?=$|\s|[.,;:?!])/g, '$1<b>$2</b>');

// 5. Itálico (_texto_)
// Regex ajustada: Aceita pontuação colada no final do underline.
text = text.replace(/(^|\s)_([^_]+)_(?=$|\s|[.,;:?!])/g, '$1<i>$2</i>');

// 6. Riscado (~texto~)
// Regex ajustada: Segue a mesma lógica de pontuação.
text = text.replace(/(^|\s)~([^~]+)~(?=$|\s|[.,;:?!])/g, '$1<strike>$2</strike>');

// 7. Links (Com a cor azul)
text = text.replace(
    /(https?:\/\/[^\s]+)/g,
    '<a href="$1" target="_blank" style="color: #0066CC; text-decoration: underline;">$1</a>'
);

// 8. Quebras de Linha
// Transforma o "Enter" invisível em <br> visível
text = text.replace(/\n/g, '<br>');

// Retorna tudo embrulhado em preto para manter o padrão visual
return `<span style="color: #333333; font-family: sans-serif; line-height: 1.5;">${text}</span>`;

