// Função que baixa a URL -> Blob -> Base64
async function urlToBase64(url) {
    // 1) Baixa o arquivo da URL
    const response = await fetch(url);
    if (!response.ok) {
        throw new Error(`Falha ao baixar áudio: ${response.status}`);
    }

    const blob = await response.blob();

    // 2) Converte Blob em base64 usando FileReader
    const base64 = await new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
            const dataUrl = reader.result; // "data:audio/ogg;base64,AAAA..."
            // se sua API quer só a parte base64, sem o "data:...,":
            const onlyBase64 = dataUrl.split(',')[1];
            resolve(onlyBase64);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
    });

    return base64;
}

const base64Audio = await urlToBase64(audioUrl);

