    file = imgs[0];
    folder = "images";
    type = "image";
} 
else if (docs && docs.length > 0) {
    file = docs[0];
    folder = "docs"; // ou "documents"
    type = "document";
} 
else if (vids && vids.length > 0) {
    file = vids[0];
    folder = "videos";
    type = "video";
}

// Segurança: Se chegou aqui sem arquivo, para tudo.
